module sr_latch (input wire S, input wire R, input wire clk, output reg obf_Q);  
    always @(posedge clk) begin  
        if (S && !R)  
            obf_Q <= 1;  
        else if (!S && R)  
            obf_Q <= 0;  
        // If both S and R are 0, obf_Q remains unchanged.  
    end  
endmodule
